import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{HttpRequest, HttpResponse}
import akka.http.scaladsl.server.Directives._
import akka.actor.ActorSystem
import akka.stream.ActorMaterializer
import scala.concurrent.Future
import scala.xml.XML

object ConfigService {
  implicit val system = ActorSystem("config-service")
  implicit val materializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  def parseXml(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    (xml \\ "setting").map { node =>
      val key = (node \ "@key").text
      val value = node.text
      key -> value
    }.toMap
  }

  val route =
    path("parse") {
      post {
        entity(as[String]) { xmlString =>
          val settings = parseXml(xmlString)
          complete(HttpResponse(entity = settings.toString()))
        }
      }
    }

  def main(args: Array[String]): Unit = {
    val bindingFuture: Future[Http.ServerBinding] = Http().bindAndHandle(route, "localhost", 8080)
    println("Server online at http://localhost:8080/")
  }
}